// Lightweight obfuscation: quiz data (including correct answers/explanations) is stored
// as base64-encoded JSON instead of plain object literals, so casual "view source" /
// right-click doesn't show answers directly. This does NOT stop someone who opens dev
// tools and actually evaluates the decoded arrays in the console — for that level of
// protection the grading would need to move server-side. Treat this as a light deterrent,
// not a security boundary.
function _dq(b64) {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return JSON.parse(new TextDecoder().decode(bytes));
}

